CREATE DATABASE FAS_DB;
GO
USE FAS_DB;

CREATE TABLE tblAdmin (
    admin_id INT IDENTITY(1, 1) PRIMARY KEY,
    name VARCHAR(100),
    username VARCHAR(50),
    password VARCHAR(50),
	position VARCHAR(100)
);



CREATE TABLE tblEmployees (
	id INT IDENTITY(1,1),
    emp_id NVARCHAR(50) PRIMARY KEY,  
    emp_name NVARCHAR(100),
    emp_bg NVARCHAR(10),
    emp_dob DATETIME2,
    emp_phone_number NVARCHAR(15),
    emp_address NVARCHAR(255),
	emp_mail nvarchar(100),
    position NVARCHAR(100),
    created_date DATETIME,
	emp_photo varbinary(max)
   );



CREATE TABLE tblAttendance (
    att_id INT IDENTITY(1,1) PRIMARY KEY,       
    FK_emp_id NVARCHAR(50),               
    time_stamp DATETIME,                   
    att_type NVARCHAR(20),                 
    FOREIGN KEY (FK_emp_id) REFERENCES tblEmployees(emp_id) 
);

CREATE TABLE tblEmbeddings (
    id INT IDENTITY(1,1) PRIMARY KEY,
    emp_id NVARCHAR(50) FOREIGN KEY REFERENCES tblEmployees(emp_id),
    embedding VARBINARY(MAX),
    created_date DATETIME
);




